/**
 * Forked from ant-design
 * Thanks to: https://github.com/ant-design/ant-design/blob/c05fd4ac55e546711be9cf1e9f9b56de8660a92f/components/input/Input.tsx#L71
 */

export function resolveOnChange(target, e, onChange, targetValue) {
  if (!onChange) {
    return;
  }
  let event = e;
  /**
   * 当点击了 clearIcon 时
   */
  if (e.type === 'click') {
    // Clone a new target for event.
    // Avoid the following usage, the setQuery method gets the original value.
    //
    // const [query, setQuery] = React.useState('');
    // <Input
    //   allowClear
    //   value={query}
    //   onChange={(e)=> {
    //     setQuery((prevStatus) => e.target.value);
    //   }}
    // />

    const currentTarget = target.cloneNode(true);

    // click clear icon
    // create 新 event 是因为 preact 不是 mutable 的 target，https://github.com/ant-design/ant-design/pull/33536
    event = Object.create(e, {
      target: {
        value: currentTarget
      },
      currentTarget: {
        value: currentTarget
      }
    });
    currentTarget.value = '';
    onChange(event);
  } else {
    // Trigger by composition event, this means we need force change the input value
    event = Object.create(e, {
      target: {
        value: target
      },
      currentTarget: {
        value: target
      }
    });

    // 如果不做此判断 safari input 下输入中文有问题
    if (target.value !== targetValue) {
      target.value = targetValue;
    }
    // console.log(event, target.value);
    onChange(event);
  }
}
